import{ISSUE_TYPES}from"../constants.js";import{ConfigurationError}from"./errors.js";export const defaultExcludedIssueTypes=["classMembers","nsExports","nsTypes"];const defaultIssueTypes=ISSUE_TYPES.filter(e=>!defaultExcludedIssueTypes.includes(e)),normalize=e=>e.flatMap(e=>e.split(","));export const shorthandDeps=["dependencies","unlisted","binaries","unresolved","catalog"];export const shorthandExports=["exports","types","enumMembers","duplicates"];export const shorthandFiles=["files"];export const getIncludedIssueTypes=e=>{const s=normalize(e.includeOverrides??[]),n=normalize(e.excludeOverrides??[]);for(const t of[...s,...n,...e.include,...e.exclude])if(!ISSUE_TYPES.includes(t))throw new ConfigurationError(`Invalid issue type: ${t}`);const t=e.exclude.filter(e=>!s.includes(e)),d=e.include.filter(e=>!n.includes(e)),i=[...s,...d],o=[...n,...t];e.isProduction?(o.push("devDependencies"),o.push("catalog")):(i.includes("dependencies")&&i.push("devDependencies","optionalPeerDependencies"),o.includes("dependencies")&&o.push("devDependencies","optionalPeerDependencies"));const r=(i.length>0?i.some(e=>!defaultExcludedIssueTypes.includes(e))?i:[...i,...defaultIssueTypes]:defaultIssueTypes).filter(e=>!o.includes(e));return Object.fromEntries(ISSUE_TYPES.map(e=>[e,r.includes(e)]))};